import{f as e,o as a,c as r,a2 as d}from"./chunks/framework.DHYrF-q6.js";const b=JSON.parse('{"title":"DevOps","description":"","frontmatter":{},"headers":[],"relativePath":"devops/index.md","filePath":"devops/index.md","lastUpdated":1780734044000}'),i={name:"devops/index.md"};function o(l,t,s,n,c,h){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="devops" tabindex="-1">DevOps <a class="header-anchor" href="#devops" aria-label="Permalink to &quot;DevOps&quot;">​</a></h1><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>DevOps 模块覆盖现代软件开发中的持续集成/持续交付（CI/CD）、容器化与编排（Docker/K8s）、Linux 基础运维以及可观测性体系建设。对于后端工程师来说，DevOps 能力已经是标配——不仅要会写代码，还要能把代码快速、稳定、安全地部署到生产环境。</p><div class="tip custom-block"><p class="custom-block-title">全栈工程师的最后一块拼图</p><p>开发、测试、部署、监控、排障的端到端能力，是高级工程师区别于初中级工程师的关键标志。</p></div><div class="info custom-block"><p class="custom-block-title">技术栈</p><p>Linux（CentOS/Ubuntu） + Docker + Kubernetes + Jenkins/GitHub Actions + Prometheus/Grafana</p></div><h2 id="核心知识点" tabindex="-1">核心知识点 <a class="header-anchor" href="#核心知识点" aria-label="Permalink to &quot;核心知识点&quot;">​</a></h2><h3 id="linux-基础" tabindex="-1">Linux 基础 <a class="header-anchor" href="#linux-基础" aria-label="Permalink to &quot;Linux 基础&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>文件系统</td><td>目录结构（FHS）、权限模型（rwx/SUID/SGID）、inode、磁盘挂载</td></tr><tr><td>进程管理</td><td>ps/top/htop、进程状态、kill 信号（-9/-15）、nohup &amp; / systemd</td></tr><tr><td>网络诊断</td><td>netstat/ss、tcpdump 抓包、curl/wget、iptables 基础</td></tr><tr><td>性能排查</td><td>CPU（top/pidstat）、内存（free/vmstat）、磁盘（iostat/iotop）、网络（iftop）</td></tr><tr><td>Shell 脚本</td><td>变量/条件/循环/函数、文本处理三剑客（grep/sed/awk）、常见排障脚本</td></tr></tbody></table><h3 id="docker" tabindex="-1">Docker <a class="header-anchor" href="#docker" aria-label="Permalink to &quot;Docker&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>核心概念</td><td>镜像/容器/仓库、分层存储（UnionFS）、写时复制（CoW）</td></tr><tr><td>镜像构建</td><td>Dockerfile 最佳实践（多阶段构建、最小化层数、.dockerignore）</td></tr><tr><td>容器管理</td><td>docker run 参数详解、端口映射、卷挂载（volume vs bind mount）、资源限制</td></tr><tr><td>网络</td><td>bridge/host/none/overlay 模式、容器间通信、自定义网络</td></tr><tr><td>Compose</td><td>多服务编排、环境变量、依赖管理（depends_on）、网络配置</td></tr><tr><td>底层原理</td><td>Namespace 隔离（PID/NET/MNT/UTS/IPC/User）、Cgroup 资源限制</td></tr></tbody></table><h3 id="kubernetes" tabindex="-1">Kubernetes <a class="header-anchor" href="#kubernetes" aria-label="Permalink to &quot;Kubernetes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>核心资源</td><td>Pod / Deployment / StatefulSet / DaemonSet / Job/CronJob</td></tr><tr><td>服务发现</td><td>Service（ClusterIP/NodePort/LoadBalancer）、Ingress / Gateway API</td></tr><tr><td>配置与存储</td><td>ConfigMap / Secret、PV/PVC/StorageClass 动态供给</td></tr><tr><td>调度与伸缩</td><td>Scheduler 调度策略、HPA（Horizontal Pod Autoscaler）、VPA</td></tr><tr><td>网络</td><td>CNI 插件（Calico/Flannel）、NetworkPolicy 网络策略</td></tr><tr><td>运维</td><td>滚动更新/蓝绿发布/金丝雀发布、资源配额（ResourceQuota/LimitRange）</td></tr><tr><td>生态工具</td><td>Helm 包管理、Kustomize 配置管理、K9s 终端管理</td></tr></tbody></table><h3 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to &quot;CI/CD&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>流水线设计</td><td>代码检出 → 编译构建 → 单元测试 → 镜像构建 → 推送仓库 → 部署发布</td></tr><tr><td>工具链</td><td>Jenkins Pipeline（Declarative/Scripted）、GitHub Actions、GitLab CI</td></tr><tr><td>策略</td><td>蓝绿部署、金丝雀发布（灰度）、滚动更新、A/B 测试</td></tr><tr><td>制品管理</td><td>Harbor/Nexus 私有镜像仓库、Maven/NPM 私服</td></tr></tbody></table><h3 id="可观测性" tabindex="-1">可观测性 <a class="header-anchor" href="#可观测性" aria-label="Permalink to &quot;可观测性&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>三支柱</td><td>Logging（日志）/ Metrics（指标）/ Tracing（链路追踪）</td></tr><tr><td>日志</td><td>ELK/EFK Stack、Filebeat 采集、日志格式规范（JSON 结构化）</td></tr><tr><td>监控</td><td>Prometheus + Grafana、核心指标（RED/USE）、自定义 Metrics、告警规则</td></tr><tr><td>链路追踪</td><td>OpenTelemetry + Jaeger/Zipkin、Trace/Span 概念、上下文传播（W3C Trace Context）</td></tr></tbody></table><h2 id="面试重点" tabindex="-1">面试重点 <a class="header-anchor" href="#面试重点" aria-label="Permalink to &quot;面试重点&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">高频考点</p><ol><li><strong>Docker vs 虚拟机</strong>：从架构层面对比差异（共享内核 vs Hypervisor），优势与局限</li><li><strong>Dockerfile 最佳实践</strong>：如何缩小镜像体积？多阶段构建解决了什么？</li><li><strong>K8s Pod 创建流程</strong>：kubectl → API Server → Scheduler → Kubelet → CRI → 容器运行</li><li><strong>K8s Service 原理</strong>：ClusterIP 如何实现负载均衡（iptables/IPVS）？NodePort/LoadBalancer 分别做了什么？</li><li><strong>CI/CD 流水线设计</strong>：代码合并到 master 后发生了什么？测试 → 构建 → 部署 → 验证全流程</li><li><strong>线上问题排查</strong>：CPU 飙升/内存泄漏/磁盘满的排查步骤和工具链</li><li><strong>可观测性建设</strong>：从零搭建一套可观测体系的思路和组件选型</li></ol></div><div class="danger custom-block"><p class="custom-block-title">容易翻车的点</p><ul><li>只有本地开发经验，没有线上部署和排查经历</li><li>K8s 概念停留在背书，没有实际操作过集群</li><li>CI/CD 仅限于 Jenkins 点个按钮，不会写 Pipeline 脚本</li><li>排查问题时只会重启服务，不会分析日志和指标</li></ul></div><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to &quot;学习建议&quot;">​</a></h2><h3 id="阶段一-linux-与-docker-2-周" tabindex="-1">阶段一：Linux 与 Docker（2 周） <a class="header-anchor" href="#阶段一-linux-与-docker-2-周" aria-label="Permalink to &quot;阶段一：Linux 与 Docker（2 周）&quot;">​</a></h3><ol><li>在本地虚拟机或云服务器安装 Linux，完成常用命令的系统学习</li><li>将你的 Spring Boot 项目 Docker 化，编写多阶段 Dockerfile</li><li>用 Docker Compose 编排一个完整的后端服务 + 数据库 + 缓存 + 消息队列环境</li></ol><h3 id="阶段二-kubernetes-入门-2-周" tabindex="-1">阶段二：Kubernetes 入门（2 周） <a class="header-anchor" href="#阶段二-kubernetes-入门-2-周" aria-label="Permalink to &quot;阶段二：Kubernetes 入门（2 周）&quot;">​</a></h3><ol start="4"><li>用 Minikube 或 Kind 本地搭建 K8s 集群</li><li>将 Docker Compose 编排的服务迁移到 K8s，编写 Deployment/Service/ConfigMap/Ingress 等 YAML</li><li>实践滚动更新、金丝雀发布、HPA 自动伸缩</li></ol><h3 id="阶段三-ci-cd-与可观测性-2-周" tabindex="-1">阶段三：CI/CD 与可观测性（2 周） <a class="header-anchor" href="#阶段三-ci-cd-与可观测性-2-周" aria-label="Permalink to &quot;阶段三：CI/CD 与可观测性（2 周）&quot;">​</a></h3><ol start="7"><li>使用 GitHub Actions 或 Jenkins 搭建 CI/CD 流水线，实现代码 Push → 自动构建 → 自动部署</li><li>搭建 Prometheus + Grafana + Loki + Tempo 可观测性全家桶</li><li>编写自定义 Exporter 暴露业务指标，配置告警规则</li></ol><h3 id="阶段四-综合实战-1-周" tabindex="-1">阶段四：综合实战（1 周） <a class="header-anchor" href="#阶段四-综合实战-1-周" aria-label="Permalink to &quot;阶段四：综合实战（1 周）&quot;">​</a></h3><ol start="10"><li>模拟一次完整的线上故障演练：注入故障 → 发现告警 → 定位问题 → 修复上线</li></ol><details class="details custom-block"><summary>推荐书单</summary><ul><li>《鸟哥的 Linux 私房菜：基础学习篇（第4版）》</li><li>《Docker 技术入门与实战（第3版）》—— 杨保华</li><li>《Kubernetes 权威指南（第5版）》—— 龚正</li><li>《Prometheus 监控实战》—— James Turnbull</li><li>《持续交付 2.0》—— 乔梁</li><li>Kubernetes 官方文档（kubernetes.io）</li></ul></details>',29)])])}const p=e(i,[["render",o]]);export{b as __pageData,p as default};
